ALTER TABLE "employees" ADD COLUMN "isQmsHead" BOOLEAN NOT NULL DEFAULT false;
CREATE TYPE "QmsTemplateStatus" AS ENUM ('DRAFT','PENDING_APPROVAL','APPROVED','RETIRED');
CREATE TYPE "QmsTemplateType" AS ENUM ('INCOMING','IN_PROCESS','FINAL','FAT','PRE_DISPATCH','INTERNAL_AUDIT','PROCESS_AUDIT','SUPPLIER_AUDIT','PRODUCT_AUDIT','FIVE_S','CUSTOM');
CREATE TYPE "QmsResponseType" AS ENUM ('YES_NO_NA','PASS_FAIL_NA','TEXT','NUMBER','MEASUREMENT','DATE','SINGLE_CHOICE','MULTIPLE_CHOICE','RATING','PHOTO','DOCUMENT','SIGNATURE');
CREATE TYPE "QmsPlanStatus" AS ENUM ('DRAFT','PENDING_APPROVAL','APPROVED','RETIRED');
CREATE TYPE "QmsInspectionStatus" AS ENUM ('DRAFT','IN_PROGRESS','PENDING_REVIEW','PASSED','CONDITIONAL_PASS','FAILED','CANCELLED');
CREATE TYPE "QmsInspectionResult" AS ENUM ('PASS','CONDITIONAL_PASS','FAIL','NOT_APPLICABLE');
CREATE TYPE "QmsControlPoint" AS ENUM ('REVIEW','WITNESS','HOLD');
CREATE TABLE "qms_question_templates" ("id" TEXT NOT NULL,"templateCode" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"templateType" "QmsTemplateType" NOT NULL,"version" INTEGER NOT NULL DEFAULT 1,"status" "QmsTemplateStatus" NOT NULL DEFAULT 'DRAFT',"effectiveFrom" TIMESTAMP(3),"createdById" TEXT NOT NULL,"submittedById" TEXT,"submittedAt" TIMESTAMP(3),"approvedById" TEXT,"approvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "qms_question_templates_pkey" PRIMARY KEY ("id"));
CREATE TABLE "qms_template_questions" ("id" TEXT NOT NULL,"templateId" TEXT NOT NULL,"section" TEXT NOT NULL,"sequence" INTEGER NOT NULL,"prompt" TEXT NOT NULL,"responseType" "QmsResponseType" NOT NULL,"required" BOOLEAN NOT NULL DEFAULT true,"weight" DECIMAL(8,2) NOT NULL DEFAULT 1,"unit" TEXT,"lowerLimit" DECIMAL(18,4),"upperLimit" DECIMAL(18,4),"options" JSONB,"acceptanceCriteria" TEXT,"evidenceOnFailure" BOOLEAN NOT NULL DEFAULT true,CONSTRAINT "qms_template_questions_pkey" PRIMARY KEY ("id"));
CREATE TABLE "qms_inspection_plans" ("id" TEXT NOT NULL,"planNumber" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"status" "QmsPlanStatus" NOT NULL DEFAULT 'DRAFT',"productId" TEXT,"orderId" TEXT,"projectKickoffId" TEXT,"revision" INTEGER NOT NULL DEFAULT 1,"createdById" TEXT NOT NULL,"submittedById" TEXT,"submittedAt" TIMESTAMP(3),"approvedById" TEXT,"approvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "qms_inspection_plans_pkey" PRIMARY KEY ("id"));
CREATE TABLE "qms_plan_stages" ("id" TEXT NOT NULL,"planId" TEXT NOT NULL,"name" TEXT NOT NULL,"stageCode" TEXT NOT NULL,"sequence" INTEGER NOT NULL,"controlPoint" "QmsControlPoint" NOT NULL DEFAULT 'REVIEW',"templateId" TEXT NOT NULL,"customerWitnessRequired" BOOLEAN NOT NULL DEFAULT false,"blocksNextStage" BOOLEAN NOT NULL DEFAULT true,"instructions" TEXT,CONSTRAINT "qms_plan_stages_pkey" PRIMARY KEY ("id"));
CREATE TABLE "qms_inspections" ("id" TEXT NOT NULL,"inspectionNumber" TEXT NOT NULL,"inspectionType" "QmsTemplateType" NOT NULL,"status" "QmsInspectionStatus" NOT NULL DEFAULT 'DRAFT',"overallResult" "QmsInspectionResult","planId" TEXT,"planStageId" TEXT,"templateSnapshot" JSONB NOT NULL,"productId" TEXT,"orderId" TEXT,"projectKickoffId" TEXT,"grnId" TEXT,"batchOrSerial" TEXT,"quantityOffered" DECIMAL(14,4),"quantityInspected" DECIMAL(14,4),"quantityAccepted" DECIMAL(14,4),"quantityRejected" DECIMAL(14,4),"assignedToId" TEXT,"inspectedById" TEXT,"inspectedAt" TIMESTAMP(3),"reviewedById" TEXT,"reviewedAt" TIMESTAMP(3),"remarks" TEXT,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "qms_inspections_pkey" PRIMARY KEY ("id"));
CREATE TABLE "qms_inspection_responses" ("id" TEXT NOT NULL,"inspectionId" TEXT NOT NULL,"questionKey" TEXT NOT NULL,"section" TEXT NOT NULL,"sequence" INTEGER NOT NULL,"promptSnapshot" TEXT NOT NULL,"responseType" "QmsResponseType" NOT NULL,"required" BOOLEAN NOT NULL,"answer" JSONB,"result" "QmsInspectionResult","comments" TEXT,"evidence" JSONB,CONSTRAINT "qms_inspection_responses_pkey" PRIMARY KEY ("id"));
