CREATE UNIQUE INDEX "qms_plan_stages_planId_stageCode_key" ON "qms_plan_stages"("planId","stageCode");
CREATE UNIQUE INDEX "qms_inspections_inspectionNumber_key" ON "qms_inspections"("inspectionNumber");
CREATE INDEX "qms_inspections_status_inspectionType_idx" ON "qms_inspections"("status","inspectionType");
CREATE INDEX "qms_inspections_grnId_idx" ON "qms_inspections"("grnId");
