ALTER TABLE "qms_plan_stages" ADD CONSTRAINT "qms_plan_stages_planId_fkey" FOREIGN KEY ("planId") REFERENCES "qms_inspection_plans"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "qms_plan_stages" ADD CONSTRAINT "qms_plan_stages_templateId_fkey" FOREIGN KEY ("templateId") REFERENCES "qms_question_templates"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
