ALTER TABLE "qms_inspection_responses" ADD CONSTRAINT "qms_inspection_responses_inspectionId_fkey" FOREIGN KEY ("inspectionId") REFERENCES "qms_inspections"("id") ON DELETE CASCADE ON UPDATE CASCADE;
